1→/* -*- Mode: C++; tab-width: 8; indent-tabs-mode: nil; c-basic-offset: 2 -*- */
     2→/* vim: set ts=8 sts=2 et sw=2 tw=80: */
     3→/* This Source Code Form is subject to the terms of the Mozilla Public
     4→ * License, v. 2.0. If a copy of the MPL was not distributed with this
     5→ * file, You can obtain one at http://mozilla.org/MPL/2.0/. */
     6→
     7→#include "mozilla/AlertNotification.h"
     8→
     9→#include "imgIContainer.h"
    10→#include "imgINotificationObserver.h"
    11→#include "imgIRequest.h"
    12→#include "imgLoader.h"
    13→#include "nsAlertsUtils.h"
    14→#include "nsAppDirectoryServiceDefs.h"
    15→#include "nsComponentManagerUtils.h"
    16→#include "nsContentUtils.h"
    17→#include "nsDirectoryServiceUtils.h"
    18→#include "nsNetUtil.h"
    19→#include "nsServiceManagerUtils.h"
    20→#include "mozilla/BasePrincipal.h"
    21→
    22→namespace mozilla {
    23→
    24→NS_IMPL_ISUPPORTS(AlertNotification, nsIAlertNotification)
    25→
    26→NS_IMETHODIMP
    27→AlertNotification::Init(const nsAString& aName, const nsAString& aImageURL,
    28→                        const nsAString& aTitle, const nsAString& aText,
    29→                        bool aTextClickable, const nsAString& aCookie,
    30→                        const nsAString& aDir, const nsAString& aLang,
    31→                        const nsAString& aData, nsIPrincipal* aPrincipal,
    32→                        bool aInPrivateBrowsing, bool aRequireInteraction,
    33→                        bool aSilent, const nsTArray<uint32_t>& aVibrate) {
    34→  if (!mId.IsEmpty()) {
    35→    return NS_ERROR_ALREADY_INITIALIZED;
    36→  }
    37→
    38→  mName = aName;
    39→  mImageURL = aImageURL;
    40→  mTitle = aTitle;
    41→  mText = aText;
    42→  mTextClickable = aTextClickable;
    43→  mCookie = aCookie;
    44→  mDir = aDir;
    45→  mLang = aLang;
    46→  mData = aData;
    47→  mPrincipal = aPrincipal;
    48→  mInPrivateBrowsing = aInPrivateBrowsing;
    49→  mRequireInteraction = aRequireInteraction;
    50→  mSilent = aSilent;
    51→  mVibrate = aVibrate.Clone();
    52→
    53→  return InitId();
    54→}
    55→
    56→NS_IMETHODIMP
    57→AlertNotification::InitWithObject(nsIAlertNotification* aAlertNotification) {
    58→  MOZ_TRY(aAlertNotification->GetName(mName));
    59→  MOZ_TRY(aAlertNotification->GetImageURL(mImageURL));
    60→  MOZ_TRY(aAlertNotification->GetImage(getter_AddRefs(mImage)));
    61→  MOZ_TRY(aAlertNotification->GetTitle(mTitle));
    62→  MOZ_TRY(aAlertNotification->GetText(mText));
    63→  MOZ_TRY(aAlertNotification->GetTextClickable(&mTextClickable));
    64→  MOZ_TRY(aAlertNotification->GetCookie(mCookie));
    65→  MOZ_TRY(aAlertNotification->GetDir(mDir));
    66→  MOZ_TRY(aAlertNotification->GetLang(mLang));
    67→  MOZ_TRY(aAlertNotification->GetData(mData));
    68→  MOZ_TRY(aAlertNotification->GetPrincipal(getter_AddRefs(mPrincipal)));
    69→  MOZ_TRY(aAlertNotification->GetInPrivateBrowsing(&mInPrivateBrowsing));
    70→  MOZ_TRY(aAlertNotification->GetRequireInteraction(&mRequireInteraction));
    71→  MOZ_TRY(aAlertNotification->GetSilent(&mSilent));
    72→  if (NS_FAILED(aAlertNotification->GetVibrate(mVibrate))) {
    73→    mVibrate.Clear();
    74→  };
    75→  nsTArray<RefPtr<nsIAlertAction>> actions;
    76→  if (NS_SUCCEEDED(aAlertNotification->GetActions(actions))) {
    77→    for (auto& action : actions) {
    78→      if (RefPtr<nsIAlertAction> copied =
    79→              AlertAction::Copy(*action).unwrapOr(nullptr)) {
    80→        mActions.AppendElement(copied);
    81→      }
    82→    }
    83→  };
    84→  return InitId();
    85→}
    86→
    87→nsresult AlertNotification::InitId() {
    88→  nsAutoString id;
    89→
    90→  // Multiple profiles might overwrite each other's toast messages when a
    91→  // common name is used for a given origin. We prevent this by including
    92→  // the profile directory as part of the toast hash.
    93→  nsCOMPtr<nsIFile> profDir;
    94→  MOZ_TRY(NS_GetSpecialDirectory(NS_APP_USER_PROFILE_50_DIR,
    95→                                 getter_AddRefs(profDir)));
    96→  MOZ_TRY(profDir->Normalize());
    97→  MOZ_TRY(profDir->GetPath(id));
    98→
    99→  if (mPrincipal && mPrincipal->GetIsContentPrincipal()) {
   100→    // Notification originated from a web notification.
   101→    nsAutoCString origin;
   102→    MOZ_TRY(mPrincipal->GetOrigin(origin));
   103→    id += NS_ConvertUTF8toUTF16(origin);
   104→  } else {
   105→    id += u"chrome";
   106→  }
   107→
   108→  if (mName.IsEmpty()) {
   109→    // No associated name, append a UUID to prevent reuse of the same tag.
   110→    nsIDToCString uuidString(nsID::GenerateUUID());
   111→    size_t len = strlen(uuidString.get());
   112→    MOZ_ASSERT(len == NSID_LENGTH - 1);
   113→    nsAutoString uuid;
   114→    CopyASCIItoUTF16(nsDependentCSubstring(uuidString.get(), len), uuid);
   115→
   116→    id += u"#notag:"_ns;
   117→    id += uuid;
   118→  } else {
   119→    id += u"#tag:"_ns;
   120→    id += mName;
   121→  }
   122→
   123→  // Windows notification tags are limited to 16 characters, or 64 characters
   124→  // after the Creators Update; therefore we hash the tag to fit the minimum
   125→  // range.
   126→  HashNumber hash = HashString(id);
   127→  mId.AppendPrintf("%010u", hash);
   128→  return NS_OK;
   129→}
   130→
   131→NS_IMETHODIMP AlertNotification::GetId(nsAString& aId) {
   132→  if (mId.IsEmpty()) {
   133→    return NS_ERROR_NOT_INITIALIZED;
   134→  }
   135→  aId = mId;
   136→  return NS_OK;
   137→}
   138→
   139→NS_IMETHODIMP
   140→AlertNotification::SetActions(
   141→    const nsTArray<RefPtr<nsIAlertAction>>& aActions) {
   142→  mActions = aActions.Clone();
   143→  return NS_OK;
   144→}
   145→
   146→NS_IMETHODIMP
   147→AlertNotification::GetName(nsAString& aName) {
   148→  if (mPrincipal && mPrincipal->GetIsContentPrincipal()) {
   149→    // mName is no longer unique, but there has been a long assumption
   150→    // throughout the codebase that GetName will be unique. So we return mId for
   151→    // GetName for web triggered notifications to keep uniqueness without
   152→    // accidentially causing subtle breakage in other modules.
   153→    aName = mId;
   154→  } else {
   155→    // System callers has always been expected to provide unique names
   156→    // themselves, so it's fine to return mName as is.
   157→    aName = mName;
   158→  }
   159→  return NS_OK;
   160→}
   161→
   162→NS_IMETHODIMP
   163→AlertNotification::GetImageURL(nsAString& aImageURL) {
   164→  aImageURL = mImageURL;
   165→  return NS_OK;
   166→}
   167→
   168→NS_IMETHODIMP
   169→AlertNotification::SetImage(imgIContainer* aImage) {
   170→  mImage = aImage;
   171→  return NS_OK;
   172→}
   173→
   174→NS_IMETHODIMP
   175→AlertNotification::GetImage(imgIContainer** aImage) {
   176→  nsCOMPtr<imgIContainer> image = mImage;
   177→  image.forget(aImage);
   178→  return NS_OK;
   179→}
   180→
   181→NS_IMETHODIMP
   182→AlertNotification::GetTitle(nsAString& aTitle) {
   183→  aTitle = mTitle;
   184→  return NS_OK;
   185→}
   186→
   187→NS_IMETHODIMP
   188→AlertNotification::GetText(nsAString& aText) {
   189→  aText = mText;
   190→  return NS_OK;
   191→}
   192→
   193→NS_IMETHODIMP
   194→AlertNotification::GetTextClickable(bool* aTextClickable) {
   195→  *aTextClickable = mTextClickable;
   196→  return NS_OK;
   197→}
   198→
   199→NS_IMETHODIMP
   200→AlertNotification::GetCookie(nsAString& aCookie) {
   201→  aCookie = mCookie;
   202→  return NS_OK;
   203→}
   204→
   205→NS_IMETHODIMP
   206→AlertNotification::GetDir(nsAString& aDir) {
   207→  aDir = mDir;
   208→  return NS_OK;
   209→}
   210→
   211→NS_IMETHODIMP
   212→AlertNotification::GetLang(nsAString& aLang) {
   213→  aLang = mLang;
   214→  return NS_OK;
   215→}
   216→
   217→NS_IMETHODIMP
   218→AlertNotification::GetRequireInteraction(bool* aRequireInteraction) {
   219→  *aRequireInteraction = mRequireInteraction;
   220→  return NS_OK;
   221→}
   222→
   223→NS_IMETHODIMP
   224→AlertNotification::GetData(nsAString& aData) {
   225→  aData = mData;
   226→  return NS_OK;
   227→}
   228→
   229→NS_IMETHODIMP
   230→AlertNotification::GetPrincipal(nsIPrincipal** aPrincipal) {
   231→  NS_IF_ADDREF(*aPrincipal = mPrincipal);
   232→  return NS_OK;
   233→}
   234→
   235→NS_IMETHODIMP
   236→AlertNotification::GetURI(nsIURI** aURI) {
   237→  if (!nsAlertsUtils::IsActionablePrincipal(mPrincipal)) {
   238→    *aURI = nullptr;
   239→    return NS_OK;
   240→  }
   241→  auto* basePrin = BasePrincipal::Cast(mPrincipal);
   242→  return basePrin->GetURI(aURI);
   243→}
   244→
   245→NS_IMETHODIMP
   246→AlertNotification::GetInPrivateBrowsing(bool* aInPrivateBrowsing) {
   247→  *aInPrivateBrowsing = mInPrivateBrowsing;
   248→  return NS_OK;
   249→}
   250→
